var pipe = $('파이프라인 조회').all().map(function(i){return i.json;});
var logRows = $('풍부화 로그 조회').all().map(function(i){return i.json;});
var enriched = {};
logRows.forEach(function(r){ if(r && r.parent_page_id) enriched[r.parent_page_id]=1; });
var cards = $('허브 목록 조회').all().map(function(i){return i.json;});
var menuLines = [];
cards.forEach(function(c){
  if(!c || !c.properties) return;
  var p = c.properties;
  var subj = (p['주제'] && p['주제'].title && p['주제'].title[0]) ? p['주제'].title[0].plain_text : '';
  if(!subj) return;
  var area = (p['영역'] && p['영역'].select) ? p['영역'].select.name : '';
  var tier = (p['계층'] && p['계층'].select) ? p['계층'].select.name : '';
  var trust = (p['신뢰등급'] && p['신뢰등급'].select) ? p['신뢰등급'].select.name : '';
  menuLines.push('- [' + area + '/' + tier + '/' + trust + '] ' + subj + ' (id: ' + c.id + ')');
});
var hubMenu = menuLines.join('\n');

var byParent = {};
pipe.forEach(function(r){
  if(!r || !r.parent_page_id) return;
  if(!byParent[r.parent_page_id]) byParent[r.parent_page_id]=[];
  byParent[r.parent_page_id].push(r);
});
var out = [];
Object.keys(byParent).forEach(function(pid){
  if(enriched[pid]) return;
  var rows = byParent[pid];
  if(!rows.length) return;
  var allCreated = rows.every(function(r){ return r.status !== 'pending'; });
  if(!allCreated) return;
  var first = rows[0];
  var stagesText = rows.map(function(r){ return r.stage + (r.persona ? '(' + r.persona + ')' : ''); }).join(', ');
  out.push({ json: {
    pageId: pid,
    title: first.title || '',
    brief: first.brief || '',
    qa: first.qa || '',
    pipeline: first.pipeline || '',
    stagesText: stagesText,
    channelId: first.channel_id || 'C0B9LE2FF36',
    threadTs: first.thread_ts || '',
    pageUrl: 'https://www.notion.so/' + String(pid).replace(/-/g, ''),
    hubMenu: hubMenu
  }});
});
return out;

