var agentOuts = $('풍부화 에이전트').all();
var ctxs = $('완료 기획 판정').all();
var locked = {};
$('허브 목록 조회').all().forEach(function(it){
  var p = it.json && it.json.properties;
  if(p && p['신뢰등급'] && p['신뢰등급'].select && p['신뢰등급'].select.name === '확정' && it.json.id) locked[it.json.id]=1;
});
var now = $now.toFormat('yyyy-LL-dd');
var HUB_DB = '3a6975952ad54380bc580901e079a7f7';

function clip(s,n){ s = (s==null)?'':String(s); return s.length>n ? s.slice(0,n) : s; }
function rtxt(t){ return [{ type:'text', text:{ content: clip(t,1900) } }]; }
function para(t){ return { object:'block', type:'paragraph', paragraph:{ rich_text: rtxt(t) } }; }
function bullet(t){ return { object:'block', type:'bulleted_list_item', bulleted_list_item:{ rich_text: rtxt(t) } }; }
function h3(t){ return { object:'block', type:'heading_3', heading_3:{ rich_text: rtxt(t) } }; }
function props(op, ctx){
  var roles = Array.isArray(op['관련직무']) ? op['관련직무'] : [];
  var o = {};
  o['주제'] = { title: [{ text:{ content: clip(op['주제']||'무제',200) } }] };
  if(op['영역']) o['영역'] = { select:{ name: op['영역'] } };
  o['관련 직무'] = { multi_select: roles.map(function(r){ return { name:r }; }) };
  if(op['계층']) o['계층'] = { select:{ name: op['계층'] } };
  o['신뢰등급'] = { select:{ name:'AI추가' } };
  if(ctx.pageUrl) o['출처'] = { url: ctx.pageUrl };
  return o;
}
function kids(op, ctx, isCreate){
  var arr = [];
  if(isCreate){ if(op.intro) arr.push(para(op.intro)); }
  else { arr.push(h3('🤖 보강 — ' + now + ' (기획: ' + clip(ctx.title,60) + ')')); }
  (Array.isArray(op.bullets)?op.bullets:[]).forEach(function(b){ arr.push(bullet(b)); });
  if(isCreate) arr.push(para('출처: ' + (ctx.pageUrl||'') + ' · 자동 풍부화(AI추가)'));
  return arr.slice(0,90);
}

var out = [];
for(var i=0;i<agentOuts.length;i++){
  var oo = (agentOuts[i].json && agentOuts[i].json.output) ? agentOuts[i].json.output : {};
  var ctx = (ctxs[i] && ctxs[i].json) ? ctxs[i].json : {};
  var ops = Array.isArray(oo.operations) ? oo.operations : [];
  var screens = Array.isArray(oo.screen_changes) ? oo.screen_changes : [];
  ops.forEach(function(op){
    var action = op.action;
    if(action === 'append' && op.cardId && locked[op.cardId]) action = 'propose';
    if(action === 'create'){
      out.push({ json:{ kind:'create', parent_db:HUB_DB, properties: props(op,ctx), children: kids(op,ctx,true), subject: op['주제']||'' } });
    } else if(action === 'append' && op.cardId){
      out.push({ json:{ kind:'append', cardId: op.cardId, children: kids(op,ctx,false), subject: op['주제']||'' } });
    } else {
      var ptext = '🧩 *[Hub 갱신 제안]* ' + (op['주제']||'') + ' (확정 카드/검토 필요)\n' + (Array.isArray(op.bullets)?op.bullets:[]).map(function(b){return '• '+b;}).join('\n') + '\n사유: ' + (op.reason||'');
      out.push({ json:{ kind:'slack', channelId: ctx.channelId, threadTs: ctx.threadTs, text: ptext } });
    }
  });
  screens.forEach(function(sc){
    var stext = '🎨 *[디자인 마스터 반영 필요]* 화면 ' + (sc['화면']||'') + ' — ' + (sc['변경']||'') + '\n' + (sc['요약']||'') + (sc.figmaNodeId ? ('\nFigma node: ' + sc.figmaNodeId) : '') + '\n(기획: ' + (ctx.title||'') + ')';
    out.push({ json:{ kind:'slack', channelId: ctx.channelId, threadTs: ctx.threadTs, text: stext } });
  });
  out.push({ json:{ kind:'slack', channelId: ctx.channelId, threadTs: ctx.threadTs, text: '📚 *[지식 풍부화 완료]* 기획 ' + (ctx.title||'') + '\n' + (oo.summary||'특이사항 없음') } });
  out.push({ json:{ kind:'log', pageId: ctx.pageId, summary: clip(oo.summary||'', 500) } });
}
return out;

